import operator
import logging
from typing import Dict, Callable

# Configure logging for production-ready error tracking
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')

def get_number(prompt: str) -> float:
    """Prompts user for a numeric input with validation."""
    while True:
        try:
            return float(input(prompt))
        except ValueError:
            logging.error("Invalid input. Please enter a valid numeric value.")

def calculate() -> None:
    """Handles the core calculation logic using the Command Pattern."""
    operations: Dict[str, Callable[[float, float], float]] = {
        '+': operator.add,
        '-': operator.sub,
        '*': operator.mul,
        '/': operator.truediv
    }

    num1 = get_number("Enter first number: ")
    op = input("Enter operator (+, -, *, /): ")
    num2 = get_number("Enter second number: ")

    if op not in operations:
        logging.error(f"Unsupported operator: '{op}'. Please use one of {list(operations.keys())}")
        return

    try:
        result = operations[op](num1, num2)
        print(f"Result: {result}")
    except ZeroDivisionError:
        logging.error("Mathematical error: Division by zero is undefined.")
    except Exception as e:
        logging.critical(f"An unexpected error occurred: {e}")

def main() -> None:
    """Main execution loop for the CLI calculator."""
    print("--- Professional CLI Calculator ---")
    while True:
        calculate()
        if input("\nPerform another calculation? (y/n): ").lower() != 'y':
            print("Exiting. Goodbye!")
            break

if __name__ == "__main__":
    main()
